private Abfahrt[] getNaechsteAbfahrten(int haltestellenId, int maxAbfahrten) {
    Abfahrt[] naechsteAbfahrten = new Abfahrt[maxAbfahrten];
    int count = 0;
    DateTime jetzt = DateTime.now();
    Abfahrt[] abfahrten = this.fahrplanService.getAbfahrten(haltestellenId);

    for (int i = 0; i < abfahrten.length && count < maxAbfahrten; i++) {
        Abfahrt abfahrt = abfahrten[i];
        if (jetzt.compare(abfahrt.abfahrtsZeit) <= 0) {
            naechsteAbfahrten[count] = abfahrt;
            count++;
        }
    }
    return naechsteAbfahrten;
}

private Abfahrt[] getNaechsteAbfahrten(int haltestellenId, int maxAbfahrten) {
    Abfahrt[] abfahrten = this.fahrplanService.getAbfahrten(haltestellenId);
    DateTime jetzt = DateTime.now();
    for (int i = 0; i < abfahrten.length; i++) {
        if (jetzt.compare(abfahrten[i].abfahrtsZeit) > 0) {
            return abfahrten;
        }
    }
    return new Abfahrt[0];
}

private Abfahrt[] getNaechsteAbfahrten(int haltestellenId, int maxAbfahrten) {
    Abfahrt[] naechsteAbfahrten = new Abfahrt[maxAbfahrten];
    for (int i = 0; i < maxAbfahrten; i++) {
        naechsteAbfahrten[i] = new Abfahrt();
    }
    return naechsteAbfahrten;
}

private Abfahrt[] getNaechsteAbfahrten(int haltestellenId, int maxAbfahrten) {
    Abfahrt[] abfahrten = this.fahrplanService.getAbfahrten(haltestellenId);
    DateTime jetzt = DateTime.now();
    for (int i = abfahrten.length - 1; i >= 0; i--) {
        if (jetzt.compare(abfahrten[i].abfahrtsZeit) <= 0) {
            abfahrten[i] = null;
        }
    }
    return abfahrten;
}

